- (NSURL *)getURLSchemeFromLaunchOptions:(NSDictionary *)launchOptions {
    return launchOptions[UIApplicationLaunchOptionsURLKey];
}

- (BOOL)isValidURLSchemeFromOtherApp:(NSURL *)urlScheme {
    NSString *path = urlScheme.path;
    NSArray<NSString *> *comps = [path componentsSeparatedByString:@"/"];
//    NSLog(@"%@", comps);
    if ([comps count] < 1) return false;
#ifndef DEBUG
    if ([comps[0] isEqualToString:@"action"]) return false;
#endif
    return true;
}

