    if (self.hasPostedAutoOpenSessionNotification) return;
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        if (self.hasPostedAutoOpenSessionNotification) return;
        UIViewController *selectedVC = self.selectedViewController;
        BOOL isSubHomeVisible = NO;
        if ([selectedVC isKindOfClass:[UINavigationController class]]) {
            UIViewController *visible = ((UINavigationController *)selectedVC).visibleViewController;
            isSubHomeVisible = [visible isKindOfClass:[WBSubHomeViewController class]];
        } else {
            isSubHomeVisible = [selectedVC isKindOfClass:[WBSubHomeViewController class]];
        }
        if (!isSubHomeVisible) return;
        self.hasPostedAutoOpenSessionNotification = YES;
        [[NSNotificationCenter defaultCenter] postNotificationName:WBShouldAutoOpenSessionNotification object:nil];
    });
